{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires relating the observed exciton binding energy to the effective Rydberg constant and then applying the hydrogenic scaling law for higher principal quantum numbers.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "Calculate the effective Rydberg energy (Ry*) using the given band gap and the 1s exciton peak energy. Note that the exciton binding energy is the difference between the band gap and the peak energy, and ensure the sign convention for binding energy is consistent with the Rydberg formula E_n = -Ry*/n^2."
    },
    {
      "label": "helper_2",
      "instructions": "Using the effective Rydberg energy (Ry*) derived in the first step, calculate the energy level for the n = 3 state using the hydrogenic model E_3 = -Ry*/n^2. Provide the final numerical value with the correct sign."
    }
  ],
  "synthesis_brief": "Subtract the 1s exciton peak energy from the band gap to find the 1s binding energy (Ry*). Use this Ry* value to calculate the energy of the n=3 state using the formula E_n = -Ry*/n^2, ensuring the negative sign is preserved."
}

